var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"중세의 성과 기사라니, 재미있는 모습이네요.","JPN":"中世の城と騎士だなんて、面白いですね。","ENG":"Knights and castles, huh. How amusing.","TWN":"看這些中世紀的場景和騎士，真有意思。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 이게 저들의 <color=#ffd34c>성역</color>의 본래 모습이었겠죠.","JPN":"おそらくこれが彼らの<color=#ffd34c>聖域</color>の本来の姿だったのでしょう。","ENG":"This must be what their original <color=#ffd34c>sanctuary</color> looked like.","TWN":"這或許就是他們的<color=#ffd34c>聖域</color>原本的樣子。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어떤가요? 스승님도 본 적 있는 광경인가요?","JPN":"どうですか？　師匠も見たことある光景ですか？","ENG":"Well? Have you ever seen anything like this before, Master?","TWN":"如何？這些場景師父應該也不陌生吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하긴, 스승님의 본명을 생각하면 이런 풍경이 더 익숙하실지도 모르겠네요.","JPN":"確かに、師匠の本名を考えると、こういう風景のほうが見慣れているかもしれませんね。","ENG":"Then again, given your real name, I guess you might feel more at home here.","TWN":"是吧？想想師父的本名，應該對這些場景很熟悉才對。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……쓸데없는 소리는 그쯤 해 둬라.","JPN":"……余計な詮索はそれぐらいにしておけ。","ENG":"…That's enough already.","TWN":"……廢話少說！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그보다 주시윤이 저 곳에 갇혀 있는 게 확실한가?","JPN":"それより、アキヤマがあそこに閉じ込められているのは確かなのか？","ENG":"Now are you sure Shiyoon is being held there?","TWN":"你確定周時雲被關在那裡嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론입니다. 스승님의 수제자를 믿으세요.","JPN":"もちろんです。師匠の一番弟子を信じてください。","ENG":"Of course. Have a little faith in your apprentice.","TWN":"當然確定！請相信你的首席大弟子。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……라고 하고 싶지만 장담하긴 어렵겠네요.","JPN":"……と言いたいところですが、断言はできませんね。","ENG":"…But to be completely honest, I'm not 100% sure.","TWN":"……雖然我很想這麼說，但我無法保證。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"납치범들이 무슨 생각을 하는지 제가 어떻게 알겠습니까? 제가 납치범인 것도 아닌데요.","JPN":"誘拐犯たちが何を考えているのか僕にはわかりません。僕が誘拐したわけではないので。","ENG":"How would I know what these kidnappers are thinking? It's not like I abducted him anyway.","TWN":"我又沒綁架過人，怎麼會知道那些綁架犯在想什麼？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러는 너도 지난번에 리플레이서 비숍을 납치하지 않았었나?","JPN":"そういうお前もこの前リプレイサー・ビショップを攫っていっただろう？","ENG":"But didn't you abduct the Replacer Bishop last time?","TWN":"你說你沒綁架過人？你上次不是才綁架過克隆·大主教嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 다 아시잖아요. 그건 상호 합의 하에 진행된 기만전술이었습니다.","JPN":"ハハ、それはもうご存知でしょう？　あれは相互合意の上で行われた欺瞞作戦でした。","ENG":"Oh, you know how it is. It was a mutually agreed upon deception tactic.","TWN":"哈哈~大家都很清楚，那是經過雙方同意的調虎離山之計不是嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"동맹과 맺은 합의도 멋대로 파기하는 무법자들과 절 비교하시면 곤란해요.","JPN":"同盟と結んだ合意を勝手に破棄するような無法者連中と僕を比べるなんて困りますよ。","ENG":"You shouldn't compare me to these lawless crackpots, who break their word on a whim.","TWN":"但他們可是隨意破壞同盟間協議的不法分子，怎麼可以把我們相提並論呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……됐다. 아무 대책 없이 쳐들어갈 생각은 아니겠지?","JPN":"……まあいい。何の対策もなく攻め込むつもりじゃないよな？","ENG":"…Forget it. You're not thinking about just barging in there, are you?","TWN":"……可以了。你應該不是想就這樣毫無策略地衝進去吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이수연과 다르게 넌 생각이라는 걸 좀 할 줄 알았던 것 같은데.","JPN":"カナミとは違って、お前は行動するより前に考えることができたと覚えているが。","ENG":"I thought you were more capable of thinking, unlike Sooyeon.","TWN":"你和李秀妍不一樣的地方，就在於你算是會思考的人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>……스승님, 방금 그 말은 대체 무슨 뜻이죠?</color>","JPN":"<color=#ffd34c>……師匠、今の言葉はいったいどういう意味ですか？</color>","ENG":"<color=#ffd34c> What's that supposed to mean, dear Master of mine?</color>","TWN":"<color=#ffd34c>……師父，你這話是什麼意思？</color>"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 그 시절 수연이가 조금 다혈질이긴 했죠.","JPN":"ハハ、あの時代のキズナはちょっと血の気が多い性格でしたね。","ENG":"Haha, Sooyeon was a bit of a hothead back in the day.","TWN":"哈哈～那個時候的秀妍是比較衝動沒錯。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어쨌든, 저들이 주시윤 군을 납치한 이유는 클리포트 게임을 앞당기기 위해서일 겁니다.","JPN":"とにかく、彼らがアキヤマ君を誘拐した理由は、クリフォトゲームを早めるためでしょう。","ENG":"Anyway, they probably captured Shiyoon to expedite the Qliphoth Game.","TWN":"總之，那些傢伙綁架周時雲是為了要提早開始逆卡巴拉遊戲。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 스승님과 제가 여기 온 것만으로도 꽤나 신경이 쓰이겠죠.","JPN":"なら、師匠と僕がここに来ただけでも用心すると思います。","ENG":"So just our presence here alone probably got their attention.","TWN":"那我和師父出現在這裡，應該就會引起他們的戒心。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 곧, 주시윤 군의 행방을 알 만큼 중요한 인물이 우릴 막으려 나설 겁니다.","JPN":"なので間もなく、アキヤマ君の行方を知っているぐらいの重要人物が僕たちを止めに来るでしょう。","ENG":"As such, someone important enough to know where Shiyoon is will try to come stop us soon.","TWN":"那知道周時雲下落的主角，應該很快就會出來阻止我們去路。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……곤란하군요. 이방인. ","JPN":"……困りますね、異邦人よ。","ENG":"…This won't do at all, ye outsider. ","TWN":"……真是傷腦筋呢！你們這些外邦人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자 님도, 알렌 님도 부재 중이실 때를 틈타 저 발키리를 이곳까지 인도해 오다니.","JPN":"救世主様やアレン様の不在に乗じて、ヴァルキリーをここまで導くなんて。","ENG":"You've brought the Valkyrie here when both the Savior and Sir Allen are absent.","TWN":"竟然趁救贖者大人和艾倫都不在的時候，把那個女武神引到這裡來。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이걸로 우리의 협력관계는 완전히 종료됐다고 생각해도 되는 거겠죠?","JPN":"これで私たちの協力関係は断絶したと考えていいのでしょう？","ENG":"Might I construe this to mean our partnership is effectively terminated?","TWN":"這麼看來，我們的合作關係應該算是終止了吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};